    return [sum(numbers[i:i+window])/window for i in range(len(numbers) - window + 1)]

def retry_execution(func, max_attempts, exceptions):
    attempts = 0
    while attempts < max_attempts:
        try:
            return func()
        except tuple(exceptions) as e:
            attempts += 1
            if attempts == max_attempts:
                raise
    return None

