def format_duration(seconds):
    if seconds == 0: return '0s'
    h = seconds // 3600
    m = (seconds % 3600) // 60
    s = seconds % 60
    parts = []
    if h > 0: parts.append(f'{h}h')
    if m > 0: parts.append(f'{m}m')
    if s > 0: parts.append(f'{s}s')
    return ' '.join(parts)

