def memoize(func):
    cache = {}
    def wrapper(*args, **kwargs):
        key = (args, frozenset(kwargs.items()))
        if key not in cache:
            cache[key] = func(*args, **kwargs)
        return cache[key]
    return wrapper

def parse_ini_config(config_string):
    result = {}
    current_section = None
    for line in config_string.splitlines():
        line = line.strip()
        if not line or line.startswith(';') or line.startswith('#'): continue
        if line.startswith('[') and line.endswith(']'):
            current_section = line[1:-1]
            result[current_section] = {}
        elif '=' in line and current_section is not None:
            key, val = line.split('=', 1)
            result[current_section][key.strip()] = val.strip()
    return result

def build_tree_from_flat_list(items):
    lookup = {item['id']: {**item, 'children': []} for item in items}
    tree = []
    for item in items:
        if item['parent_id'] is None:
            tree.append(lookup[item['id']])
        else:
            lookup[item['parent_id']]['children'].append(lookup[item['id']])
    return tree

import re
def convert_markdown_headers(markdown_text):
    lines = markdown_text.splitlines()
    for i, line in enumerate(lines):
        match = re.match(r'^(#{1,6})\s+(.*)$', line)
        if match:
            level = len(match.group(1))
            content = match.group(2)
            lines[i] = f'<h{level}>{content}</h{level}>'
    return '\n'.join(lines)

class LRUCache:
    def __init__(self, capacity):
        self.capacity = capacity
        self.cache = {}
    def get(self, key):
        if key not in self.cache: return -1
        val = self.cache.pop(key)
        self.cache[key] = val
        return val
    def put(self, key, value):
        if key in self.cache:
            self.cache.pop(key)
        self.cache[key] = value
        if len(self.cache) > self.capacity:
            self.cache.pop(next(iter(self.cache)))

def merge_intervals(intervals):
    if not intervals: return []
    intervals.sort(key=lambda x: x[0])
    merged = [intervals[0]]
    for current in intervals[1:]:
        previous = merged[-1]
        if current[0] <= previous[1]:
            previous[1] = max(previous[1], current[1])
        else:
            merged.append(current)
    return merged

def evaluate_rpn(tokens):
    stack = []
    for token in tokens:
        if token in '+-*/':
            b, a = stack.pop(), stack.pop()
            if token == '+': stack.append(a + b)
            elif token == '-': stack.append(a - b)
            elif token == '*': stack.append(a * b)
            elif token == '/': stack.append(int(a / b))
        else:
            stack.append(int(token))
    return stack[0]

def find_longest_palindromic_substring(s):
    if not s: return ''
    best_start, best_len = 0, 1
    def expand(left, right):
        while left >= 0 and right < len(s) and s[left] == s[right]:
            left -= 1
            right += 1
        return left + 1, right - left - 1
    for i in range(len(s)):
        s1, l1 = expand(i, i)
        s2, l2 = expand(i, i + 1)
        if l1 > best_len:
            best_start, best_len = s1, l1
        if l2 > best_len:
            best_start, best_len = s2, l2
    return s[best_start:best_start + best_len]

def regex_matcher(s, p):
    cache = {}
    def dfs(i, j):
        if (i, j) in cache: return cache[(i, j)]
        if j == len(p): return i == len(s)
        match = i < len(s) and (s[i] == p[j] or p[j] == '.')
        if j + 1 < len(p) and p[j+1] == '*':
            res = dfs(i, j + 2) or (match and dfs(i + 1, j))
        else:
            res = match and dfs(i + 1, j + 1)
        cache[(i, j)] = res
        return res
    return dfs(0, 0)

import xml.etree.ElementTree as ET
def xml_to_dict(xml_str):
    def _to_dict(elem):
        if not list(elem):
            return elem.text.strip() if elem.text else ''
        result = {}
        for child in elem:
            child_dict = _to_dict(child)
            if child.tag in result:
                if type(result[child.tag]) is list:
                    result[child.tag].append(child_dict)
                else:
                    result[child.tag] = [result[child.tag], child_dict]
            else:
                result[child.tag] = child_dict
        return result
    root = ET.fromstring(xml_str)
    return {root.tag: _to_dict(root)}

